type StringOrNumber = string | number;

function format(value: StringOrNumber): string {
  if (typeof value === "string") {
    return value.toUpperCase();
  }
  return value.toFixed(2);
}

// Discriminated union â€” the TypeScript pattern
type Circle = { kind: "circle"; radius: number };
type Rectangle = { kind: "rectangle"; width: number; height: number };
type Triangle = { kind: "triangle"; base: number; height: number };

type Shape = Circle | Rectangle | Triangle;

function area(shape: Shape): number {
  switch (shape.kind) {
    case "circle":
      return Math.PI * shape.radius ** 2;
    case "rectangle":
      return shape.width * shape.height;
    case "triangle":
      return 0.5 * shape.base * shape.height;
  }
}

console.log(area({ kind: "circle", radius: 5 })); // 78.54

// Exhaustive checking
function assertNever(x: never): never {
  throw new Error(`Unexpected: ${x}`);
}

function describe(shape: Shape): string {
  switch (shape.kind) {
    case "circle": return `Circle r=${shape.radius}`;
    case "rectangle": return `Rect ${shape.width}x${shape.height}`;
    case "triangle": return `Triangle b=${shape.base}`;
    default: return assertNever(shape); // error if case missing!
  }
}

// Intersection types
type Draggable = { drag: () => void };
type Resizable = { resize: (w: number, h: number) => void };

type UIWidget = Draggable & Resizable;

const widget: UIWidget = {
  drag() { console.log("dragging"); },
  resize(w, h) { console.log(`resizing to ${w}x${h}`); },
};

// Discriminated union for API responses
type Success<T> = { status: "ok"; data: T };
type Failure = { status: "error"; message: string };
type Result<T> = Success<T> | Failure;

function handleResult<T>(result: Result<T>): T | null {
  if (result.status === "ok") {
    return result.data;  // narrowed to Success<T>
  }
  console.error(result.message);  // narrowed to Failure
  return null;
}
