// Method decorator â€” logging
defunction Log(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const original = descriptor.value;
  descriptor.value = function (...args: any[]) {
    console.log(`Calling ${propertyKey} with`, args);
    const result = original.apply(this, args);
    console.log(`${propertyKey} returned`, result);
    return result;
  };
}

// Class decorator
defunction Sealed(constructor: Function) {
  Object.seal(constructor);
  Object.seal(constructor.prototype);
}

// Parameterized decorator factory
defunction RateLimit(limit: number, windowMs: number) {
  const calls: number[] = [];
  return function (target: any, propertyKey: string, descriptor: PropertyDescriptor) {
    const original = descriptor.value;
    descriptor.value = function (...args: any[]) {
      const now = Date.now();
      const recentCalls = calls.filter(t => now - t < windowMs);
      if (recentCalls.length >= limit) {
        throw new Error(`Rate limit exceeded for ${propertyKey}`);
      }
      calls.push(now);
      return original.apply(this, args);
    };
  };
}

@Sealed
class Calculator {
  @Log
  add(a: number, b: number): number {
    return a + b;
  }

  @RateLimit(5, 1000)
  expensiveOperation(): void {
    console.log("Working...");
  }
}

